import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XssFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Encoding user input before outputting it to the webpage
        try {
            String encodedInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("<div>" + encodedInput + "</div>");
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
